import React from 'react';
import { Link } from 'react-router-dom'; // Importa Link para la navegación interna

const Footer = () => {
  return (
    <footer style={styles.footerContainer}>
      <div style={styles.footerContent}>
        {/* Sección 1: Más información */}
        <div style={styles.section}>
          <h3 style={styles.sectionTitle}>más información</h3>
          <ul style={styles.linkListSingle}>
            <li><Link to="/empresas" style={styles.link}>Empresas</Link></li>
            <li><Link to="/historia" style={styles.link}>Nuestra Historia</Link></li>
            <li><a href="#" style={styles.link}>Novedades</a></li>
            <li><Link to="/contacto" style={styles.link}>Contacto</Link></li>
          </ul>
        </div>

        {/* Sección 2: Encuéntranos / Club de Correo / Redes Sociales */}
        <div style={styles.sectionCenter}>
          <h3 style={styles.sectionTitle}>encuéntranos</h3>
          {/* El botón "UBICADOR DE TIENDAS" ahora lleva a "Nuestra Historia" (el equivalente a "nosotros") */}
          <Link to="/historia" style={{ textDecoration: 'none' }}>
            <button style={styles.storeLocatorButton}>ACERCA DE NOSOTROS</button>
          </Link>

          <h3 style={{ ...styles.sectionTitle, marginTop: '15px' }}>club de correo</h3>
          <p style={styles.emailClubText}>Mantente al día con nuestras noticias y ofertas.</p>
          <div style={styles.emailInputContainer}>
            <input type="email" placeholder="tu correo electrónico" style={styles.emailInput} />
            <button style={styles.emailSubmitButton}>&rarr;</button>
          </div>
          <div style={styles.socialIcons}>
            {/* Reemplaza los href y src con tus enlaces e imágenes reales */}
            <a href="https://www.facebook.com/TuPaginaDeFacebook" target="_blank" rel="noopener noreferrer" style={styles.socialIconLink}>
              <img src="/media/icons/facebook_icon.png" alt="Facebook" style={styles.socialIconImage} />
            </a>
            <a href="https://www.instagram.com/TuCuentaDeInstagram" target="_blank" rel="noopener noreferrer" style={styles.socialIconLink}>
              <img src="/media/icons/instagram_icon.png" alt="Instagram" style={styles.socialIconImage} />
            </a>
            <a href="https://www.tiktok.com/@TuCuentaDeTikTok" target="_blank" rel="noopener noreferrer" style={styles.socialIconLink}>
              <img src="/media/icons/tiktok_icon.png" alt="TikTok" style={styles.socialIconImage} />
            </a>
          </div>
        </div>

        {/* Sección 3: Necesitas ayuda? */}
        <div style={styles.section}>
          <h3 style={styles.sectionTitle}>necesitas ayuda?</h3>
          <ul style={styles.linkListSingle}>
            <li><Link to="/contacto" style={styles.link}>Contacta con nosotros</Link></li>
            <li><Link to="/privacidad" style={styles.link}>Política de Privacidad</Link></li>
            <li><a href="#" style={styles.link}>Términos del servicio</a></li>
            <li><a href="#" style={styles.link}>Preguntas frecuentes</a></li>
          </ul>
        </div>
      </div>

      {/* Sección de créditos "Titulizado por Alberto Navarro" */}
      <div style={styles.creditsBar}>
        <p style={styles.creditsText}>Titulizado por Alberto Navarro</p>
      </div>
    </footer>
  );
};

const styles = {
  footerContainer: {
    backgroundImage: "url('/media/footer2.png')", // Aseguramos que esté aquí para que se vea el diseño
    backgroundSize: 'cover',
    backgroundPosition: 'center',
    backgroundRepeat: 'no-repeat',
    backgroundColor: '#F8F6F1', // Color de fondo de respaldo
    padding: '25px 15px 10px 15px', // Aún más pequeño el padding vertical
    color: '#333',
    fontFamily: "'Poppins', sans-serif",
    borderTop: '1px solid #eee',
    boxShadow: '0 -2px 8px rgba(0,0,0,0.03)', // Sombra más sutil
  },
  footerContent: {
    display: 'flex',
    justifyContent: 'space-around',
    flexWrap: 'wrap',
    maxWidth: '880px', // Ancho máximo ajustado
    margin: '0 auto',
    gap: '20px', // Espacio entre columnas
    marginBottom: '10px', // Espacio entre contenido y créditos
  },
  section: {
    flex: '1 1 160px', // Flex-basis aún más pequeño
    minWidth: '140px',
  },
  sectionCenter: {
    flex: '1 1 260px', // Flex-basis aún más pequeño
    minWidth: '180px',
    textAlign: 'center',
    display: 'flex',
    flexDirection: 'column',
    alignItems: 'center',
  },
  sectionTitle: {
    fontSize: '1.05rem', // Ligeramente más grande
    fontWeight: 'bold',
    marginBottom: '10px', // Margen más pequeño
    textTransform: 'uppercase',
    color: '#333',
  },
  linkListSingle: {
    listStyle: 'none',
    padding: 0,
    margin: 0,
    lineHeight: '1.4', // Espaciado entre elementos de la lista
  },
  link: {
    textDecoration: 'none',
    color: '#555',
    fontSize: '0.9rem', // Ligeramente más grande
    transition: 'color 0.3s ease, transform 0.2s ease',
    display: 'inline-block',
    '&:hover': {
      color: '#166D3B',
      transform: 'translateX(2px)', // Desplazamiento sutil
    },
  },
  storeLocatorButton: {
    backgroundColor: '#28a745',
    color: 'white',
    border: 'none',
    padding: '8px 16px', // Padding más pequeño
    borderRadius: '4px',
    cursor: 'pointer',
    fontSize: '0.85rem', // Ligeramente más grande
    fontWeight: 'bold',
    textTransform: 'uppercase',
    marginTop: '5px',
    letterSpacing: '0.5px',
    transition: 'background-color 0.3s ease, transform 0.2s ease',
    '&:hover': {
      backgroundColor: '#1e7e34',
      transform: 'scale(1.02)', // Zoom sutil
    },
    '&:active': {
      transform: 'scale(0.98)',
    }
  },
  emailClubText: {
    fontSize: '0.85rem', // Ligeramente más grande
    color: '#666',
    marginBottom: '8px',
    lineHeight: '1.3',
  },
  emailInputContainer: {
    display: 'flex',
    width: '90%',
    maxWidth: '220px', // Ancho máximo aún más pequeño
    borderBottom: '1px solid #999',
    paddingBottom: '2px',
    marginBottom: '12px', // Margen más pequeño
    alignItems: 'center',
  },
  emailInput: {
    flexGrow: 1,
    border: 'none',
    outline: 'none',
    backgroundColor: 'transparent',
    fontSize: '0.9rem', // Ligeramente más grande
    color: '#333',
    padding: '2px 0',
    '&::placeholder': {
      color: '#bbb',
    },
  },
  emailSubmitButton: {
    background: 'none',
    border: 'none',
    fontSize: '1rem', // Ligeramente más grande
    color: '#555',
    cursor: 'pointer',
    padding: '2px',
    transition: 'color 0.3s ease, transform 0.2s ease',
    '&:hover': {
      color: '#166D3B',
      transform: 'translateX(2px)',
    },
  },
  socialIcons: {
    display: 'flex',
    gap: '15px', // Espacio entre íconos reducido
    marginTop: '10px', // Margen superior reducido
  },
  socialIconLink: {
    textDecoration: 'none',
  },
  socialIconImage: {
    width: '24px', // Tamaño de los iconos
    height: '24px',
    opacity: 0.8,
    transition: 'opacity 0.3s ease, transform 0.2s ease',
    '&:hover': {
      opacity: 1,
      transform: 'scale(1.1)',
    },
  },
  creditsBar: {
    textAlign: 'center',
    fontSize: '0.8rem', // Ligeramente más grande que antes
    color: '#666',
    paddingTop: '6px', // Padding superior reducido
    borderTop: '1px solid #eee',
    marginTop: 'auto',
  },
  creditsText: {
    margin: 0,
  },
};

export default Footer;
